/**
 * @fileType unit-test
 * @domain exercises
 * @pattern ui-test, student-renderer, layout
 * @ai-summary Unit tests for side-by-side layout of axis blocks with rich text
 */
import { describe, expect, it, vi } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import React from 'react'
import type { ContentBlock, QuestionAxisBlock, RichTextBlock } from '@/server/payload/collections/Exercises/types'
import type { AxisSpecV1 } from '@/infra/contracts/graphics/axis.v1'

// Mock ExerciseRenderer with side-by-side logic
// The actual implementation needs to:
// 1. Detect axis blocks with displaySize != 'full'
// 2. Group them with adjacent rich_text blocks
// 3. Apply flex layout

interface ExerciseContent {
  blocks: ContentBlock[]
}

interface MockExerciseRendererProps {
  content: ExerciseContent
  mode?: 'student' | 'debug'
}

// Helper to create axis blocks
const createAxisBlock = (displaySize?: 'small' | 'medium' | 'large' | 'full'): QuestionAxisBlock => ({
  id: 'axis-1',
  type: 'question_axis',
  prompt: {
    type: 'rich_text',
    format: 'md-math-v1',
    value: 'Graph the function',
    mediaIds: [],
  },
  axis: {
    kind: 'cartesian',
    units: 1,
    grid: { enabled: true, color: '#e0e0e0' },
    axes: {
      showNumbers: true,
      showLabels: true,
      ticks: 1,
      labels: { x: 'x', y: 'y' },
      origin: { x: 0, y: 0 },
    },
    viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
    elements: { points: [], graphs: [] },
  },
  displaySize,
})

// Helper to create rich text blocks
const createRichTextBlock = (value: string): RichTextBlock => ({
  id: 'rt-1',
  type: 'rich_text',
  format: 'md-math-v1',
  value,
  mediaIds: [],
})

// Mock renderer that implements side-by-side logic
const MockExerciseRenderer: React.FC<MockExerciseRendererProps> = ({ content, mode = 'student' }) => {
  const blocks = content.blocks
  const elements: React.ReactNode[] = []
  let i = 0

  while (i < blocks.length) {
    const block = blocks[i]

    // Check if this is an axis block with non-full displaySize
    if (block.type === 'question_axis') {
      const axisBlock = block as QuestionAxisBlock
      const displaySize = axisBlock.displaySize || 'full'

      // Look ahead to see if next block is rich_text and displaySize is not 'full'
      const nextBlock = blocks[i + 1]
      const hasAdjacentText = nextBlock && nextBlock.type === 'rich_text'

      if (displaySize !== 'full' && hasAdjacentText) {
        // Side-by-side layout
        const textBlock = nextBlock as RichTextBlock

        elements.push(
          <div 
            key={`side-by-side-${i}`} 
            data-testid="side-by-side-container"
            className="flex gap-4 items-start"
          >
            <div 
              data-testid="axis-wrapper"
              data-width={displaySize}
              style={{ width: displaySize === 'small' ? '33%' : displaySize === 'medium' ? '50%' : '75%' }}
              className="flex-shrink-0"
            >
              <div data-testid="axis-block">Axis Graph</div>
            </div>
            <div 
              data-testid="text-wrapper"
              className="flex-1 min-w-0"
            >
              <div data-testid="rich-text-block">{textBlock.value}</div>
            </div>
          </div>
        )

        // Skip the next block since we rendered it here
        i += 2
        continue
      }
    }

    // Regular rendering (not side-by-side)
